-- Migration 17: Enneagram (RHETI-style 36 forced-choice sampler) — schema + items.
-- Each item carries a type for statement A (gift_letter) and statement B
-- (option_b_letter). Answer value is 0 (chose A) or 1 (chose B). Type key
-- verified against two source PDFs; every type appears in exactly 8 pairs.
-- Seeded unpublished; publish with:
--   update assessments set is_published=true where slug='enneagram';
begin;

-- Forced-choice needs a second statement + its type key on each item.
alter table items add column if not exists option_b_text text;
alter table items add column if not exists option_b_letter text;

insert into assessments (slug,name,subtitle,category,scale_min,scale_max,estimated_minutes,questions_per_page,sensitivity,is_published)
values ('enneagram','Enneagram Type Assessment','A Redemptive Personality Reflection','personal',0,1,10,9,'standard',false)
on conflict (slug) do update set
  name=excluded.name, subtitle=excluded.subtitle, category=excluded.category,
  scale_min=excluded.scale_min, scale_max=excluded.scale_max,
  estimated_minutes=excluded.estimated_minutes, questions_per_page=excluded.questions_per_page,
  sensitivity=excluded.sensitivity;
delete from items where assessment_id=(select id from assessments where slug='enneagram');
with a as (select id from assessments where slug='enneagram')
insert into items (assessment_id,item_order,text,gift_letter,option_b_text,option_b_letter,domain,is_scored,is_reverse_scored,item_type)
select a.id,v.ord,v.txt,v.al,v.btxt,v.bl,v.dom,v.sc,v.rev,v.it::item_type
from a,(values (1,'I''ve been romantic and imaginative.','4','I''ve been pragmatic and down to earth.','6','enneagram',true,false,'standard'),(2,'I have tended to take on confrontations.','8','I have tended to avoid confrontations.','9','enneagram',true,false,'standard'),(3,'I have typically been diplomatic, charming, and ambitious.','3','I have typically been direct, formal, and idealistic.','1','enneagram',true,false,'standard'),(4,'I have tended to be focused and intense.','5','I have tended to be spontaneous and fun-loving.','7','enneagram',true,false,'standard'),(5,'I have been a hospitable person and have enjoyed welcoming new friends into my life.','2','I have been a private person and have not mixed much with others.','4','enneagram',true,false,'standard'),(6,'Generally, it''s been easy to "get a rise" out of me.','6','Generally, it''s been difficult to "get a rise" out of me.','9','enneagram',true,false,'standard'),(7,'I''ve been more of a "street-smart" survivor.','8','I''ve been more of a "high-minded" idealist.','1','enneagram',true,false,'standard'),(8,'I have needed to show affection to people.','2','I have preferred to maintain a certain distance with people.','5','enneagram',true,false,'standard'),(9,'When presented with a new experience, I''ve usually asked myself if it would be useful to me.','3','When presented with a new experience, I''ve usually asked myself if it would be enjoyable.','7','enneagram',true,false,'standard'),(10,'I have tended to focus too much on myself.','4','I have tended to focus too much on others.','9','enneagram',true,false,'standard'),(11,'Others have depended on my insight and knowledge.','5','Others have depended on my strength and decisiveness.','8','enneagram',true,false,'standard'),(12,'I have come across as being too unsure of myself.','6','I have come across as being too sure of myself.','1','enneagram',true,false,'standard'),(13,'I have been more relationship-oriented than goal-oriented.','2','I have been more goal-oriented than relationship-oriented.','3','enneagram',true,false,'standard'),(14,'I have not been able to speak up for myself very well.','4','I have been outspoken; I''ve said what others wished they had the nerve to say.','7','enneagram',true,false,'standard'),(15,'It''s been difficult for me to stop considering alternatives and do something definite.','5','It''s been difficult for me to take it easy and be more flexible.','1','enneagram',true,false,'standard'),(16,'I have tended to be hesitant and procrastinating.','6','I have tended to be bold and domineering.','8','enneagram',true,false,'standard'),(17,'My reluctance to get too involved has gotten me into trouble with people.','9','My eagerness to have people depend on me has gotten me into trouble with them.','2','enneagram',true,false,'standard'),(18,'Usually, I have been able to put my feelings aside to get the job done.','3','Usually, I have needed to work through my feelings before I could act.','4','enneagram',true,false,'standard'),(19,'Generally, I have been methodical and cautious.','6','Generally, I have been adventurous and taken risks.','7','enneagram',true,false,'standard'),(20,'I have tended to be a supportive, giving person who enjoys the company of others.','2','I have tended to be a serious, reserved person who likes discussing issues.','1','enneagram',true,false,'standard'),(21,'I''ve often felt the need to be a "pillar of strength."','8','I''ve often felt the need to perform perfectly.','3','enneagram',true,false,'standard'),(22,'I''ve typically been interested in asking tough questions and maintaining my independence.','5','I''ve typically been interested in maintaining my stability and peace of mind.','9','enneagram',true,false,'standard'),(23,'I''ve been too hard-nosed and skeptical.','6','I''ve been too soft-hearted and sentimental.','2','enneagram',true,false,'standard'),(24,'I''ve often worried that I''m missing out on something better.','7','I''ve often worried that if I let down my guard, someone will take advantage of me.','8','enneagram',true,false,'standard'),(25,'My habit of being "stand-offish" has annoyed people.','4','My habit of telling people what to do has annoyed people.','1','enneagram',true,false,'standard'),(26,'Usually, when troubles have gotten to me, I have been able to "tune them out."','9','Usually, when troubles have gotten to me, I have treated myself to something I''ve enjoyed.','7','enneagram',true,false,'standard'),(27,'I have depended upon my friends, and they have known that they can depend on me.','6','I have not depended on people; I have done things on my own.','3','enneagram',true,false,'standard'),(28,'I have tended to be detached and preoccupied.','5','I have tended to be moody and self-absorbed.','4','enneagram',true,false,'standard'),(29,'I have liked to challenge people and "shake them up."','8','I have liked to comfort people and calm them down.','2','enneagram',true,false,'standard'),(30,'I have generally been an outgoing, sociable person.','7','I have generally been an earnest, self-disciplined person.','1','enneagram',true,false,'standard'),(31,'I''ve usually been shy about showing my abilities.','9','I''ve usually liked to let people know what I can do well.','3','enneagram',true,false,'standard'),(32,'Pursuing my personal interests has been more important to me than having comfort and security.','5','Having comfort and security has been more important to me than pursuing my personal interests.','6','enneagram',true,false,'standard'),(33,'When I''ve had conflicts with others, I''ve tended to withdraw.','4','When I''ve had conflicts with others, I''ve rarely backed down.','8','enneagram',true,false,'standard'),(34,'I have given in too easily and let others push me around.','9','I have been too uncompromising and demanding with others.','1','enneagram',true,false,'standard'),(35,'I''ve been appreciated for my unsinkable spirit and great sense of humor.','7','I''ve been appreciated for my quiet strength and exceptional generosity.','2','enneagram',true,false,'standard'),(36,'Much of my success has been due to my talent for making a favorable impression.','3','Much of my success has been achieved despite my lack of interest in developing "interpersonal skills."','5','enneagram',true,false,'standard')) as v(ord,txt,al,btxt,bl,dom,sc,rev,it);
commit;
